     1→"use client";
     2→
     3→import { useAuth } from "@/entities/auth";
     4→import { APP_ROUTES } from "@/shared/config/app-routes";
     5→import { CreateTicketForm } from "@/widgets/create-ticket-form";
     6→import Link from "next/link";
     7→import { useRouter } from "next/navigation";
     8→
     9→export default function CreateTicketPage() {
    10→  const router = useRouter();
    11→  const { isAuthenticated, isLoading } = useAuth();
    12→
    13→  function handleSuccess() {
    14→    if (isAuthenticated) {
    15→      router.push(APP_ROUTES.TICKETS.ROOT);
    16→    } else {
    17→      router.push("/");
    18→    }
    19→  }
    20→
    21→  return (
    22→    <div className="mx-auto max-w-[600px]">
    23→      <Link
    24→        href={isAuthenticated ? APP_ROUTES.TICKETS.ROOT : "/"}
    25→        className="mb-8 inline-flex items-center gap-2 rounded-full border border-[#D6D3D1] bg-white px-4 py-2 font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
    26→      >
    27→        <svg
    28→          width="14"
    29→          height="14"
    30→          viewBox="0 0 16 16"
    31→          fill="none"
    32→          aria-hidden="true"
    33→        >
    34→          <path
    35→            d="M13 8H3M7 4L3 8l4 4"
    36→            stroke="currentColor"
    37→            strokeWidth="1.5"
    38→            strokeLinecap="round"
    39→            strokeLinejoin="round"
    40→          />
    41→        </svg>
    42→        Back
    43→      </Link>
    44→
    45→      <h1 className="font-light font-new-serif text-[#44403C] text-[2rem] leading-[120%]">
    46→        Raise a Support Ticket
    47→      </h1>
    48→      <p className="mt-2 font-new-sans text-[#A8A29E] text-sm">
    49→        Share enough details to get your issue resolved. Our team will evaluate
    50→        your request and will address it soon.
    51→      </p>
    52→
    53→      <div className="my-6 border-[#D6D3D1] border-t" />
    54→
    55→      {isLoading ? (
    56→        <div className="flex flex-col gap-4">
    57→          {[1, 2, 3].map((i) => (
    58→            <div key={i} className="h-12 animate-pulse rounded-[4px] bg-[#EDE9E3]" />
    59→          ))}
    60→        </div>
    61→      ) : (
    62→        <CreateTicketForm
    63→          isGuest={!isAuthenticated}
    64→          onSuccess={handleSuccess}
    65→        />
    66→      )}
    67→    </div>
    68→  );
    69→}
    70→

