     1→"use client";
     2→
     3→import { useAdminTickets } from "@/shared/api/query-hooks/use-tickets-admin";
     4→import { APP_ROUTES } from "@/shared/config/app-routes";
     5→import {
     6→  ACTIVE_TICKET_STATUSES,
     7→  ARCHIVE_TICKET_STATUSES,
     8→} from "@/shared/constants/ticket";
     9→import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/shared/ui/tabs";
    10→import { TicketsTable } from "@/widgets/tickets-table";
    11→import { useRouter, useSearchParams } from "next/navigation";
    12→import { Suspense, useState } from "react";
    13→
    14→function AdminTicketsContent() {
    15→  const router = useRouter();
    16→  const searchParams = useSearchParams();
    17→  const tab = searchParams.get("tab") || "active";
    18→
    19→  const [activeTab, setActiveTab] = useState(tab);
    20→
    21→  const { data: activeTicketsData, isLoading: isLoadingActive } =
    22→    useAdminTickets(
    23→      {
    24→        statuses: ACTIVE_TICKET_STATUSES,
    25→      },
    26→      activeTab === "active",
    27→    );
    28→
    29→  const { data: archiveTicketsData, isLoading: isLoadingArchive } =
    30→    useAdminTickets(
    31→      {
    32→        statuses: ARCHIVE_TICKET_STATUSES,
    33→      },
    34→      activeTab === "archive",
    35→    );
    36→
    37→  function handleTabChange(value: string) {
    38→    setActiveTab(value);
    39→    router.push(
    40→      value === "active"
    41→        ? APP_ROUTES.ADMIN.TICKETS.ROOT
    42→        : APP_ROUTES.ADMIN.TICKETS.ARCHIVE,
    43→    );
    44→  }
    45→
    46→  function handleRowClick(ticketId: string) {
    47→    router.push(APP_ROUTES.ADMIN.TICKETS.DETAIL(ticketId));
    48→  }
    49→
    50→  return (
    51→    <div className="container mx-auto px-4 py-8">
    52→      <h1 className="mb-8 font-bold font-serif text-3xl text-foreground">
    53→        Support Tickets
    54→      </h1>
    55→
    56→      <Tabs value={activeTab} onValueChange={handleTabChange}>
    57→        <TabsList variant="default">
    58→          <TabsTrigger variant="default" value="active">
    59→            Active
    60→          </TabsTrigger>
    61→          <TabsTrigger variant="default" value="archive">
    62→            Archive
    63→          </TabsTrigger>
    64→        </TabsList>
    65→
    66→        <TabsContent value="active" className="mt-6">
    67→          <TicketsTable
    68→            tickets={activeTicketsData?.data || []}
    69→            isLoading={isLoadingActive}
    70→            onRowClick={handleRowClick}
    71→          />
    72→        </TabsContent>
    73→
    74→        <TabsContent value="archive" className="mt-6">
    75→          <TicketsTable
    76→            tickets={archiveTicketsData?.data || []}
    77→            isLoading={isLoadingArchive}
    78→            onRowClick={handleRowClick}
    79→          />
    80→        </TabsContent>
    81→      </Tabs>
    82→    </div>
    83→  );
    84→}
    85→
    86→export default function AdminTicketsPage() {
    87→  return (
    88→    <Suspense
    89→      fallback={<div className="container mx-auto py-8">Loading...</div>}
    90→    >
    91→      <AdminTicketsContent />
    92→    </Suspense>
    93→  );
    94→}
