     1→"use client";
     2→
     3→import { useCreateTicket } from "@/shared/api/query-hooks/use-tickets";
     4→import { Checkbox } from "@/shared/ui/checkbox";
     5→import { toast } from "@/shared/ui/notification";
     6→import {
     7→  Select,
     8→  SelectContent,
     9→  SelectItem,
    10→  SelectTrigger,
    11→  SelectValue,
    12→} from "@/shared/ui/select";
    13→import { zodResolver } from "@hookform/resolvers/zod";
    14→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
    15→import { type Resolver, useForm } from "react-hook-form";
    16→import { z } from "zod";
    17→
    18→import {
    19→  useActiveBuybacks,
    20→  useBuybackRequests,
    21→} from "@/shared/api/query-hooks/use-buyback-requests";
    22→import { useFileUpload } from "@/shared/api/query-hooks/use-file-upload";
    23→import type { MimeType } from "@/shared/constants/mime-types";
    24→import { S3_FOLDERS } from "@/shared/constants/mime-types";
    25→import { TICKET_CATEGORY_LABELS } from "@/shared/constants/ticket";
    26→import { sanitizeFileName } from "@/shared/lib/utils/file-name-utils";
    27→import { NotificationMedia, TicketCategory } from "@/shared/types/ticket.types";
    28→import type { CreateTicketFormProps } from "../model/types";
    29→
    30→const MAX_FILES = 5;
    31→const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5 MB
    32→
    33→const createTicketSchema = z.object({
    34→  description: z
    35→    .string()
    36→    .min(1, "Description is required")
    37→    .min(5, "Description must be at least 5 characters")
    38→    .max(2000, "Description must be less than 2000 characters"),
    39→  category: z.nativeEnum(TicketCategory, {
    40→    errorMap: () => ({ message: "Please select a category" }),
    41→  }),
    42→  referenceId: z.string().optional(),
    43→  attachedFileIds: z.array(z.string()).max(MAX_FILES, `Maximum ${MAX_FILES} files allowed`),
    44→  preferredContactMethods: z
    45→    .array(z.nativeEnum(NotificationMedia))
    46→    .min(1, "Select at least one contact method"),
    47→});
    48→
    49→const guestCreateTicketSchema = createTicketSchema.extend({
    50→  fullName: z.string().min(1, "Full name is required").min(2, "Name must be at least 2 characters"),
    51→  email: z.string().min(1, "Email is required").email("Please enter a valid email"),
    52→});
    53→
    54→type GuestCreateTicketFormData = z.infer<typeof guestCreateTicketSchema>;
    55→
    56→export function CreateTicketForm({ onSuccess, onCancel, isGuest = false }: CreateTicketFormProps) {
    57→  const [uploadedFiles, setUploadedFiles] = useState<Array<{ id: string; name: string }>>([]);
    58→  const [isUploadingFiles, setIsUploadingFiles] = useState(false);
    59→  const [isDragOver, setIsDragOver] = useState(false);
    60→  const [referenceSearch, setReferenceSearch] = useState("");
    61→  const [debouncedSearch, setDebouncedSearch] = useState("");
    62→  const [isReferenceSelectOpen, setIsReferenceSelectOpen] = useState(false);
    63→  const fileInputRef = useRef<HTMLInputElement>(null);
    64→
    65→  const createTicketMutation = useCreateTicket();
    66→  const fileUploadMutation = useFileUpload();
    67→
    68→  const schema = isGuest ? guestCreateTicketSchema : createTicketSchema;
    69→
    70→  const {
    71→    register,
    72→    handleSubmit,
    73→    watch,
    74→    setValue,
    75→    formState: { errors },
    76→  } = useForm<GuestCreateTicketFormData>({
    77→    resolver: zodResolver(schema) as unknown as Resolver<GuestCreateTicketFormData>,
    78→    defaultValues: {
    79→      attachedFileIds: [],
    80→      preferredContactMethods: [NotificationMedia.Email],
    81→    },
    82→  });
    83→
    84→  const selectedCategory = watch("category");
    85→  const selectedContactMethods = watch("preferredContactMethods");
    86→  const selectedReferenceId = watch("referenceId");
    87→
    88→  useEffect(() => {
    89→    const timer = setTimeout(() => {
    90→      setDebouncedSearch(referenceSearch);
    91→    }, 300);
    92→
    93→    return () => clearTimeout(timer);
    94→  }, [referenceSearch]);
    95→
    96→  const { data: buybacksData, isLoading: isLoadingBuybacks } = useActiveBuybacks({
    97→    search: debouncedSearch || undefined,
    98→  });
    99→
   100→  const { data: buybackRequestsData, isLoading: isLoadingBuybackRequests } = useBuybackRequests({
   101→    search: debouncedSearch || undefined,
   102→  });
   103→
   104→  function handleContactMethodToggle(method: NotificationMedia) {
   105→    const current = selectedContactMethods || [];
   106→
   107→    if (current.includes(method)) {
   108→      const newMethods = current.filter((m) => m !== method);
   109→
   110→      if (newMethods.length === 0) {
   111→        toast.error("At least one contact method is required");
   112→
   113→        return;
   114→      }
   115→
   116→      setValue("preferredContactMethods", newMethods, { shouldValidate: true });
   117→    } else {
   118→      setValue("preferredContactMethods", [...current, method], { shouldValidate: true });
   119→    }
   120→  }
   121→
   122→  async function processFiles(files: File[]) {
   123→    const remainingSlots = MAX_FILES - uploadedFiles.length;
   124→
   125→    if (remainingSlots <= 0) {
   126→      toast.error(`Maximum ${MAX_FILES} files allowed`);
   127→
   128→      return;
   129→    }
   130→
   131→    const filesToProcess = files.slice(0, remainingSlots);
   132→    const oversized = files.filter((f) => f.size > MAX_FILE_SIZE);
   133→
   134→    if (oversized.length > 0) {
   135→      toast.error(`${oversized.length} file(s) exceed the 5 MB limit`);
   136→    }
   137→
   138→    const validFiles = filesToProcess.filter((f) => f.size <= MAX_FILE_SIZE);
   139→
   140→    if (validFiles.length === 0) return;
   141→
   142→    setIsUploadingFiles(true);
   143→
   144→    const uploadResults: Array<{ id: string; name: string }> = [];
   145→
   146→    for (const file of validFiles) {
   147→      try {
   148→        const fileNameInfo = sanitizeFileName(file.name);
   149→
   150→        const result = await fileUploadMutation.mutateAsync({
   151→          file,
   152→          mime: file.type as MimeType,
   153→          fileName: fileNameInfo.sanitized,
   154→          folder: S3_FOLDERS.FILES,
   155→        });
   156→
   157→        uploadResults.push({ id: result.fileId, name: fileNameInfo.original });
   158→      } catch {
   159→        toast.error(`Failed to upload ${file.name}`);
   160→      }
   161→    }
   162→
   163→    const newUploadedFiles = [...uploadedFiles, ...uploadResults];
   164→
   165→    setUploadedFiles(newUploadedFiles);
   166→    setValue("attachedFileIds", newUploadedFiles.map((f) => f.id), { shouldValidate: true });
   167→
   168→    setIsUploadingFiles(false);
   169→  }
   170→
   171→  function handleRemoveFile(fileId: string) {
   172→    const newUploadedFiles = uploadedFiles.filter((f) => f.id !== fileId);
   173→
   174→    setUploadedFiles(newUploadedFiles);
   175→    setValue("attachedFileIds", newUploadedFiles.map((f) => f.id), { shouldValidate: true });
   176→  }
   177→
   178→  const handleDragOver = useCallback((e: React.DragEvent) => {
   179→    e.preventDefault();
   180→    setIsDragOver(true);
   181→  }, []);
   182→
   183→  const handleDragLeave = useCallback((e: React.DragEvent) => {
   184→    e.preventDefault();
   185→    setIsDragOver(false);
   186→  }, []);
   187→
   188→  function handleDrop(e: React.DragEvent) {
   189→    e.preventDefault();
   190→    setIsDragOver(false);
   191→
   192→    const files = Array.from(e.dataTransfer.files);
   193→    const accepted = files.filter((f) =>
   194→      ["application/pdf", "image/jpeg", "image/png"].includes(f.type),
   195→    );
   196→
   197→    if (accepted.length < files.length) {
   198→      toast.error("Only .PDF, .JPG, .PNG files are supported");
   199→    }
   200→
   201→    if (accepted.length > 0) {
   202→      processFiles(accepted);
   203→    }
   204→  }
   205→
   206→  // biome-ignore lint/suspicious/noExplicitAny: dynamic schema union
   207→  async function onSubmit(data: any) {
   208→    const subject = data.description.slice(0, 100).trim() || "Support Request";
   209→
   210→    createTicketMutation.mutate(
   211→      {
   212→        subject,
   213→        description: data.description,
   214→        category: data.category,
   215→        referenceId: data.referenceId,
   216→        attachedFileIds: data.attachedFileIds,
   217→        preferredContactMethods: data.preferredContactMethods,
   218→      },
   219→      {
   220→        onSuccess: () => {
   221→          toast.success("Ticket submitted successfully");
   222→          onSuccess?.();
   223→        },
   224→        onError: () => {
   225→          toast.error("Failed to create ticket");
   226→        },
   227→      },
   228→    );
   229→  }
   230→
   231→  const referenceOptions = useMemo(() => {
   232→    if (selectedCategory === TicketCategory.ActiveBuyback) {
   233→      return (
   234→        buybacksData?.data.map((b) => ({
   235→          value: b.id,
   236→          label: `Buyback #${b.id.slice(0, 8)}`,
   237→          details: `${b.asset.category.name} · ${b.asset.brand.name} · ${b.asset.model.name}`,
   238→        })) || []
   239→      );
   240→    }
   241→
   242→    if (selectedCategory === TicketCategory.BuybackRequest) {
   243→      return (
   244→        buybackRequestsData?.data.map((br) => ({
   245→          value: br.id,
   246→          label: `Request #${br.id.slice(0, 8)}`,
   247→          details: `${br.buyback.asset.category.name} · ${br.buyback.asset.brand.name} · ${br.buyback.asset.model.name}`,
   248→        })) || []
   249→      );
   250→    }
   251→
   252→    return [];
   253→  }, [selectedCategory, buybacksData, buybackRequestsData]);
   254→
   255→  const isLoadingReference =
   256→    selectedCategory === TicketCategory.ActiveBuyback ? isLoadingBuybacks : isLoadingBuybackRequests;
   257→
   258→  const showReferenceSelect =
   259→    !isGuest &&
   260→    (selectedCategory === TicketCategory.ActiveBuyback || selectedCategory === TicketCategory.BuybackRequest);
   261→
   262→  const descriptionValue = watch("description") || "";
   263→  const isSubmitting = createTicketMutation.isPending || isUploadingFiles;
   264→
   265→  return (
   266→    <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col gap-6">
   267→      {/* Guest fields */}
   268→      {isGuest && (
   269→        <div className="flex flex-col gap-4 sm:flex-row">
   270→          <div className="flex flex-1 flex-col gap-1.5">
   271→            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
   272→              Full Name <span className="text-red-500">*</span>
   273→            </label>
   274→            <input
   275→              {...register("fullName")}
   276→              placeholder="Your full name"
