   157→    skip,
   158→  });
   159→  const { data: summary, isLoading: summaryLoading } =
   160→    useWalletTransactionsSummary();
   161→
   162→  const handleNextPage = () => {
   163→    setSkip((prev) => prev + ITEMS_PER_PAGE);
   164→  };
   165→
   166→  const handlePrevPage = () => {
   167→    setSkip((prev) => Math.max(0, prev - ITEMS_PER_PAGE));
   168→  };
   169→
   170→  const transactions = data?.data || [];
   171→  const total = data?.total || 0;
   172→  const hasNextPage = skip + ITEMS_PER_PAGE < total;
   173→  const hasPrevPage = skip > 0;
   174→  const showingFrom = total === 0 ? 0 : skip + 1;
   175→  const showingTo = Math.min(skip + ITEMS_PER_PAGE, total);
   176→
   177→  const paginationProps = {
   178→    showingFrom,
   179→    showingTo,
   180→    total,
   181→    hasPrevPage,
   182→    hasNextPage,
   183→    onPrev: handlePrevPage,
   184→    onNext: handleNextPage,
