     1→"use client";
     2→
     3→import { signOut } from "next-auth/react";
     4→import { usePathname, useRouter } from "next/navigation";
     5→import type { ReactNode } from "react";
     6→
     7→import { APP_ROUTES } from "@/shared/config/app-routes";
     8→import { SELLER_SIDEBAR_ITEMS } from "@/shared/config/sidebar-config";
     9→import { useSidebarContext } from "@/shared/contexts/sidebar-context";
    10→import { Sidebar } from "@/shared/ui/sidebar";
    11→
    12→const NEW_DESIGN_ROUTES = [
    13→  "/wallet",
    14→  "/buyback-requests/create",
    15→  "/my-deals",
    16→  "/buyback-requests",
    17→  "/buybacks",
    18→  "/tickets",
    19→];
    20→
    21→export default function SidebarLayout({ children }: { children: ReactNode }) {
    22→  const router = useRouter();
    23→  const pathname = usePathname();
    24→  const { isOpen, setIsOpen } = useSidebarContext();
    25→
    26→  const isBuybackPayPage =
    27→    pathname.startsWith("/buybacks/") && pathname.endsWith("/pay");
    28→
    29→  if (
    30→    NEW_DESIGN_ROUTES.some((route) => pathname.startsWith(route)) ||
    31→    isBuybackPayPage
    32→  ) {
    33→    return <>{children}</>;
    34→  }
    35→
    36→  function getActiveItem() {
    37→    for (const item of SELLER_SIDEBAR_ITEMS) {
    38→      if (item.path === pathname) {
    39→        return item.value;
    40→      }
    41→
    42→      if (item.subItems) {
    43→        for (const subItem of item.subItems) {
    44→          if (subItem.path === pathname) {
    45→            return subItem.value;
    46→          }
    47→        }
    48→      }
    49→    }
    50→
    51→    for (const item of SELLER_SIDEBAR_ITEMS) {
    52→      if (item.subItems) {
    53→        for (const subItem of item.subItems) {
    54→          const basePath = subItem.path.split("?")[0];
    55→          if (
    56→            pathname.startsWith(basePath) &&
    57→            (pathname[basePath.length] === "?" ||
    58→              pathname[basePath.length] === "/" ||
    59→              pathname.length === basePath.length)
    60→          ) {
    61→            return subItem.value;
    62→          }
    63→        }
    64→      }
    65→    }
    66→
    67→    const firstSegment = pathname.split("/")[1];
    68→
    69→    return firstSegment || "profile";
    70→  }
    71→
    72→  const isNewDesign = NEW_DESIGN_ROUTES.some(
    73→    (route) => pathname === route || pathname.startsWith(`${route}/`)
    74→  );
    75→
    76→  const activeItem = getActiveItem();
    77→
    78→  async function handleItemClick(value: string, path?: string) {
    79→    if (value === "logout") {
    80→      await signOut({ redirect: false });
    81→      router.push(APP_ROUTES.AUTH.SIGN_IN);
    82→      router.refresh();
    83→
    84→      return;
    85→    }
    86→
    87→    if (path && path !== "#") {
    88→      router.push(path);
    89→    }
    90→  }
    91→
    92→  const isFullWidthPage = pathname === APP_ROUTES.PROFILE;
    93→
    94→  if (isFullWidthPage) {
    95→    return <>{children}</>;
    96→  }
    97→
    98→  return (
    99→    <div className="flex min-h-full w-full flex-col md:flex-row">
   100→      <Sidebar
   101→        activeItem={activeItem}
   102→        isOpen={isOpen}
   103→        items={SELLER_SIDEBAR_ITEMS}
   104→        onItemClick={handleItemClick}
   105→        onOpenChange={setIsOpen}
   106→      />
   107→      <div className="flex-1 px-3 pt-4 pb-6 sm:px-4 sm:pt-8 lg:max-w-[calc(100vw-266px)] lg:pt-8">
   108→        {children}
   109→      </div>
   110→    </div>
   111→  );
   112→}
